INSERT INTO `quiz_categories` (`id`, `name`, `description`, `sort_order`, `status`, `created_at`, `instructions`, `duration_minutes`, `total_questions`, `persona_code`, `meta_json`) VALUES (5,'Technical Freshers','PERSONA 01\nExperience  ·  0 years        Context  ·  B2C focus        Difficulty  ·  Foundational\n\nThis 200-item assessment has been designed for technical graduates (BTech, BCA, MCA) who are about to enter the workforce or are in their first 6 months of professional life. Items are calibrated to the foundational professional competencies a technically-trained fresh graduate must develop to transition into commercial work effectively.\nWhy this assessment is different\nUnlike single-format knowledge tests, this instrument uses six psychometrically distinct item types — Knowledge MCQs, Situatio…',1,'active','2026-06-25 17:26:20','ELEVATES   |   PROFESSIONAL GROWTH ASSESSMENT\nPERSONA 01 — Technical Freshers\nExperience  ·  0 years        Context  ·  B2C focus        Difficulty  ·  Foundational\n\nA 200-item, multi-format, psychometrically structured assessment covering five pillars of professional growth.\n\nFIVE PILLARS ASSESSED\n01  Value Selling Mastery\n02  Leadership & Influence\n03  Personality & Communication\n04  Mental Wellness & Resilience\n05  Technology & Digital Fluency\n\nABOUT THIS ASSESSMENT\nThis 200-item assessment has been designed for technical graduates (BTech, BCA, MCA) who are about to enter the workforce or are in their first 6 months of professional life. Items are calibrated to the foundational professional competencies a technically-trained fresh graduate must develop to transition into commercial work effectively.\nWhy this assessment is different\nUnlike single-format knowledge tests, this instrument uses six psychometrically distinct item types — Knowledge MCQs, Situational Judgment items with weighted scoring, Self-Concept Inventory Likert items, Reverse-Coded items (which detect response-bias), Behavioral Frequency items, and Forced-Choice items. This multi-format design follows the same principles used by international assessment publishers (e.g., SHL, Kenexa/IBM, CAPP, SOVA) and reflects best practice from peer-reviewed research on Situational Judgment Tests (Whetzel, Sullivan & McCloy, 2020) and competency-based rubrics.\n\nHOW TO TAKE THIS ASSESSMENT\nAnswer every item honestly. Self-concept items have no \'right\' answer — they measure your perception of yourself, which is most useful when truthful. Situational judgment items present realistic scenarios where multiple responses are plausible — choose the response you would most likely give in real life, not the response you think is \'correct\'.\n\nTIME REQUIRED: 75–90 minutes. May be split across two sittings.\n\nITEM TYPES IN THIS ASSESSMENT\n• K — Knowledge MCQ: One correct answer. Choose the best response based on your knowledge.\n• SJT — Situational Judgment: All options are plausible. Choose what you would most likely do in real life.\n• SCI — Self-Concept Inventory: No right or wrong answer — answer honestly about yourself.\n• SCI-R — Reverse-Coded Self-Concept: No right or wrong answer — answer honestly (some items are reverse-coded).\n• BEH — Behavioral Frequency: Rate how often this applies to you (Never → Always).\n• FC — Forced Choice: Select the BEST and WORST option from the choices given.\n\nPILLAR WEIGHTS (for composite score)\n• Value Selling Mastery — 40 items (18%)\n• Leadership & Influence — 40 items (18%)\n• Personality & Communication — 50 items (22%)\n• Mental Wellness & Resilience — 35 items (17%)\n• Technology & Digital Fluency — 35 items (25%)\n\nPROFICIENCY BANDS\n• ADVANCED (85–100): Demonstrates sustained mastery. Ready for senior responsibility, mentoring others, and leading complex initiatives.\n• PROFICIENT (70–84): Reliably effective in most situations. Benefits from stretch assignments and exposure to higher-complexity challenges.\n• COMPETENT (50–69): Solid foundation with room to deepen. Coaching, applied practice, and structured feedback will accelerate development.\n• EMERGING (30–49): Foundational understanding but inconsistent application. Needs targeted skill-building and supervised practice.\n• DEVELOPING (0–29): Significant gap. Requires intensive learning, mentorship, and behavioral coaching before independent responsibility is appropriate.',90,200,'P1','{\"header\":\"ELEVATES   |   PROFESSIONAL GROWTH ASSESSMENT\",\"persona\":\"PERSONA 01\",\"title\":\"Technical Freshers\",\"name\":\"Technical Freshers\",\"context_line\":\"Experience  ·  0 years        Context  ·  B2C focus        Difficulty  ·  Foundational\",\"tagline\":\"A 200-item, multi-format, psychometrically structured assessment covering five pillars of professional growth.\",\"pillars\":[{\"num\":\"01\",\"name\":\"Value Selling Mastery\"},{\"num\":\"02\",\"name\":\"Leadership & Influence\"},{\"num\":\"03\",\"name\":\"Personality & Communication\"},{\"num\":\"04\",\"name\":\"Mental Wellness & Resilience\"},{\"num\":\"05\",\"name\":\"Technology & Digital Fluency\"}],\"about\":\"This 200-item assessment has been designed for technical graduates (BTech, BCA, MCA) who are about to enter the workforce or are in their first 6 months of professional life. Items are calibrated to the foundational professional competencies a technically-trained fresh graduate must develop to transition into commercial work effectively.\\nWhy this assessment is different\\nUnlike single-format knowledge tests, this instrument uses six psychometrically distinct item types — Knowledge MCQs, Situational Judgment items with weighted scoring, Self-Concept Inventory Likert items, Reverse-Coded items (which detect response-bias), Behavioral Frequency items, and Forced-Choice items. This multi-format design follows the same principles used by international assessment publishers (e.g., SHL, Kenexa\\/IBM, CAPP, SOVA) and reflects best practice from peer-reviewed research on Situational Judgment Tests (Whetzel, Sullivan & McCloy, 2020) and competency-based rubrics.\",\"how_to\":\"Answer every item honestly. Self-concept items have no \'right\' answer — they measure your perception of yourself, which is most useful when truthful. Situational judgment items present realistic scenarios where multiple responses are plausible — choose the response you would most likely give in real life, not the response you think is \'correct\'.\",\"time_required\":\"75–90 minutes. May be split across two sittings.\",\"pillar_weights\":[{\"num\":\"01\",\"name\":\"Value Selling Mastery\",\"items\":40,\"weight\":\"18%\",\"weight_pct\":18},{\"num\":\"02\",\"name\":\"Leadership & Influence\",\"items\":40,\"weight\":\"18%\",\"weight_pct\":18},{\"num\":\"03\",\"name\":\"Personality & Communication\",\"items\":50,\"weight\":\"22%\",\"weight_pct\":22},{\"num\":\"04\",\"name\":\"Mental Wellness & Resilience\",\"items\":35,\"weight\":\"17%\",\"weight_pct\":17},{\"num\":\"05\",\"name\":\"Technology & Digital Fluency\",\"items\":35,\"weight\":\"25%\",\"weight_pct\":25}],\"scoring_steps\":[\"STEP 1  Compute the raw score for each pillar by summing item-level scores using the Answer Key. Knowledge items contribute 0–1; SJT items contribute 0–3; Self-concept and behavioral items contribute 1–5.\",\"STEP 2  Convert each pillar\'s raw score to a percentage of its maximum possible score: Pillar % = (raw \\/ max) × 100. Round to one decimal place.\",\"STEP 3  Compute the Composite Score as the weighted average of pillar percentages: Composite = Σ (Pillar % × Pillar Weight) ÷ 100.\",\"STEP 4  Map both pillar percentages and composite score to the five proficiency bands in section 4 to derive the descriptive level and recommended interventions.\"],\"proficiency_bands\":[{\"min\":85,\"max\":100,\"title\":\"ADVANCED\",\"descriptor\":\"Demonstrates sustained mastery. Ready for senior responsibility, mentoring others, and leading complex initiatives.\"},{\"min\":70,\"max\":84,\"title\":\"PROFICIENT\",\"descriptor\":\"Reliably effective in most situations. Benefits from stretch assignments and exposure to higher-complexity challenges.\"},{\"min\":50,\"max\":69,\"title\":\"COMPETENT\",\"descriptor\":\"Solid foundation with room to deepen. Coaching, applied practice, and structured feedback will accelerate development.\"},{\"min\":30,\"max\":49,\"title\":\"EMERGING\",\"descriptor\":\"Foundational understanding but inconsistent application. Needs targeted skill-building and supervised practice.\"},{\"min\":0,\"max\":29,\"title\":\"DEVELOPING\",\"descriptor\":\"Significant gap. Requires intensive learning, mentorship, and behavioral coaching before independent responsibility is appropriate.\"}],\"item_types\":[{\"code\":\"K\",\"name\":\"Knowledge MCQ\",\"hint\":\"One correct answer. Choose the best response based on your knowledge.\"},{\"code\":\"SJT\",\"name\":\"Situational Judgment\",\"hint\":\"All options are plausible. Choose what you would most likely do in real life.\"},{\"code\":\"SCI\",\"name\":\"Self-Concept Inventory\",\"hint\":\"No right or wrong answer — answer honestly about yourself.\"},{\"code\":\"SCI-R\",\"name\":\"Reverse-Coded Self-Concept\",\"hint\":\"No right or wrong answer — answer honestly (some items are reverse-coded).\"},{\"code\":\"BEH\",\"name\":\"Behavioral Frequency\",\"hint\":\"Rate how often this applies to you (Never → Always).\"},{\"code\":\"FC\",\"name\":\"Forced Choice\",\"hint\":\"Select the BEST and WORST option from the choices given.\"}],\"code\":\"P1\",\"sort_order\":1,\"slug\":\"technical-freshers\"}'),(6,'Management Freshers','PERSONA 02\nExperience  ·  0 years        Context  ·  B2C focus        Difficulty  ·  Foundational–Intermediate\n\nThis 200-item assessment is designed for MBA graduates entering the workforce. Items focus on consultative selling, leadership in early-career contexts, and the management foundations expected of business school graduates. Compared to the Technical Freshers assessment, this version weights Leadership and Value Selling more heavily, and Technology more lightly — reflecting the difference in professional context.',2,'active','2026-06-25 17:31:34','ELEVATES   |   PROFESSIONAL GROWTH ASSESSMENT\nPERSONA 02 — Management Freshers\nExperience  ·  0 years        Context  ·  B2C focus        Difficulty  ·  Foundational–Intermediate\n\nA 200-item, multi-format, psychometrically structured assessment covering five pillars of professional growth.\n\nFIVE PILLARS ASSESSED\n01  Value Selling Mastery\n02  Leadership & Influence\n03  Personality & Communication\n04  Mental Wellness & Resilience\n05  Technology & Digital Fluency\n\nABOUT THIS ASSESSMENT\nThis 200-item assessment is designed for MBA graduates entering the workforce. Items focus on consultative selling, leadership in early-career contexts, and the management foundations expected of business school graduates. Compared to the Technical Freshers assessment, this version weights Leadership and Value Selling more heavily, and Technology more lightly — reflecting the difference in professional context.\n\nHOW TO TAKE THIS ASSESSMENT\nSix psychometrically distinct item types are used. Self-concept items have no \'right\' answer — they measure your self-perception. Situational judgment items present realistic scenarios where multiple responses are plausible — choose what you would most likely do in real life, not what you think we want to hear.\n\nTIME REQUIRED: 75–90 minutes. May be split across two sittings.\n\nITEM TYPES IN THIS ASSESSMENT\n• K — Knowledge MCQ: One correct answer. Choose the best response based on your knowledge.\n• SJT — Situational Judgment: All options are plausible. Choose what you would most likely do in real life.\n• SCI — Self-Concept Inventory: No right or wrong answer — answer honestly about yourself.\n• SCI-R — Reverse-Coded Self-Concept: No right or wrong answer — answer honestly (some items are reverse-coded).\n• BEH — Behavioral Frequency: Rate how often this applies to you (Never → Always).\n• FC — Forced Choice: Select the BEST and WORST option from the choices given.\n\nPILLAR WEIGHTS (for composite score)\n• Value Selling Mastery — 45 items (22%)\n• Leadership & Influence — 50 items (25%)\n• Personality & Communication — 45 items (22%)\n• Mental Wellness & Resilience — 35 items (16%)\n• Technology & Digital Fluency — 25 items (15%)\n\nPROFICIENCY BANDS\n• ADVANCED (85–100): Demonstrates sustained mastery. Ready for senior responsibility, mentoring others, and leading complex initiatives.\n• PROFICIENT (70–84): Reliably effective in most situations. Benefits from stretch assignments and exposure to higher-complexity challenges.\n• COMPETENT (50–69): Solid foundation with room to deepen. Coaching, applied practice, and structured feedback will accelerate development.\n• EMERGING (30–49): Foundational understanding but inconsistent application. Needs targeted skill-building and supervised practice.\n• DEVELOPING (0–29): Significant gap. Requires intensive learning, mentorship, and behavioral coaching before independent responsibility is appropriate.',90,200,'P2','{\"header\":\"ELEVATES   |   PROFESSIONAL GROWTH ASSESSMENT\",\"persona\":\"PERSONA 02\",\"title\":\"Management Freshers\",\"name\":\"Management Freshers\",\"context_line\":\"Experience  ·  0 years        Context  ·  B2C focus        Difficulty  ·  Foundational–Intermediate\",\"tagline\":\"A 200-item, multi-format, psychometrically structured assessment covering five pillars of professional growth.\",\"pillars\":[{\"num\":\"01\",\"name\":\"Value Selling Mastery\"},{\"num\":\"02\",\"name\":\"Leadership & Influence\"},{\"num\":\"03\",\"name\":\"Personality & Communication\"},{\"num\":\"04\",\"name\":\"Mental Wellness & Resilience\"},{\"num\":\"05\",\"name\":\"Technology & Digital Fluency\"}],\"about\":\"This 200-item assessment is designed for MBA graduates entering the workforce. Items focus on consultative selling, leadership in early-career contexts, and the management foundations expected of business school graduates. Compared to the Technical Freshers assessment, this version weights Leadership and Value Selling more heavily, and Technology more lightly — reflecting the difference in professional context.\",\"how_to\":\"Six psychometrically distinct item types are used. Self-concept items have no \'right\' answer — they measure your self-perception. Situational judgment items present realistic scenarios where multiple responses are plausible — choose what you would most likely do in real life, not what you think we want to hear.\",\"time_required\":\"75–90 minutes. May be split across two sittings.\",\"pillar_weights\":[{\"num\":\"01\",\"name\":\"Value Selling Mastery\",\"items\":45,\"weight\":\"22%\",\"weight_pct\":22},{\"num\":\"02\",\"name\":\"Leadership & Influence\",\"items\":50,\"weight\":\"25%\",\"weight_pct\":25},{\"num\":\"03\",\"name\":\"Personality & Communication\",\"items\":45,\"weight\":\"22%\",\"weight_pct\":22},{\"num\":\"04\",\"name\":\"Mental Wellness & Resilience\",\"items\":35,\"weight\":\"16%\",\"weight_pct\":16},{\"num\":\"05\",\"name\":\"Technology & Digital Fluency\",\"items\":25,\"weight\":\"15%\",\"weight_pct\":15}],\"scoring_steps\":[\"STEP 1  Compute the raw score for each pillar by summing item-level scores using the Answer Key. Knowledge items contribute 0–1; SJT items contribute 0–3; Self-concept and behavioral items contribute 1–5.\",\"STEP 2  Convert each pillar\'s raw score to a percentage of its maximum possible score: Pillar % = (raw \\/ max) × 100. Round to one decimal place.\",\"STEP 3  Compute the Composite Score as the weighted average of pillar percentages: Composite = Σ (Pillar % × Pillar Weight) ÷ 100.\",\"STEP 4  Map both pillar percentages and composite score to the five proficiency bands in section 4 to derive the descriptive level and recommended interventions.\"],\"proficiency_bands\":[{\"min\":85,\"max\":100,\"title\":\"ADVANCED\",\"descriptor\":\"Demonstrates sustained mastery. Ready for senior responsibility, mentoring others, and leading complex initiatives.\"},{\"min\":70,\"max\":84,\"title\":\"PROFICIENT\",\"descriptor\":\"Reliably effective in most situations. Benefits from stretch assignments and exposure to higher-complexity challenges.\"},{\"min\":50,\"max\":69,\"title\":\"COMPETENT\",\"descriptor\":\"Solid foundation with room to deepen. Coaching, applied practice, and structured feedback will accelerate development.\"},{\"min\":30,\"max\":49,\"title\":\"EMERGING\",\"descriptor\":\"Foundational understanding but inconsistent application. Needs targeted skill-building and supervised practice.\"},{\"min\":0,\"max\":29,\"title\":\"DEVELOPING\",\"descriptor\":\"Significant gap. Requires intensive learning, mentorship, and behavioral coaching before independent responsibility is appropriate.\"}],\"item_types\":[{\"code\":\"K\",\"name\":\"Knowledge MCQ\",\"hint\":\"One correct answer. Choose the best response based on your knowledge.\"},{\"code\":\"SJT\",\"name\":\"Situational Judgment\",\"hint\":\"All options are plausible. Choose what you would most likely do in real life.\"},{\"code\":\"SCI\",\"name\":\"Self-Concept Inventory\",\"hint\":\"No right or wrong answer — answer honestly about yourself.\"},{\"code\":\"SCI-R\",\"name\":\"Reverse-Coded Self-Concept\",\"hint\":\"No right or wrong answer — answer honestly (some items are reverse-coded).\"},{\"code\":\"BEH\",\"name\":\"Behavioral Frequency\",\"hint\":\"Rate how often this applies to you (Never → Always).\"},{\"code\":\"FC\",\"name\":\"Forced Choice\",\"hint\":\"Select the BEST and WORST option from the choices given.\"}],\"code\":\"P2\",\"sort_order\":2,\"slug\":\"management-freshers\"}'),(7,'Working Professionals','PERSONA 03\nExperience  ·  3–15 years        Context  ·  B2C context        Difficulty  ·  Intermediate–Advanced\n\nThis 200-item assessment is designed for mid-career professionals (3-15 years of experience) working in B2C contexts. Items reflect the complexity of leading teams, managing accounts, navigating mid-career identity, and operating in a digital-first commercial environment. Calibration is significantly more demanding than the fresher assessments - distractors are subtler and scenarios closer to lived complexity.',3,'active','2026-06-25 17:31:35','ELEVATES   |   PROFESSIONAL GROWTH ASSESSMENT\nPERSONA 03 — Working Professionals\nExperience  ·  3–15 years        Context  ·  B2C context        Difficulty  ·  Intermediate–Advanced\n\nA 200-item, multi-format, psychometrically structured assessment covering five pillars of professional growth.\n\nFIVE PILLARS ASSESSED\n01  Value Selling Mastery\n02  Leadership & Influence\n03  Personality & Communication\n04  Mental Wellness & Resilience\n05  Technology & Digital Fluency\n\nABOUT THIS ASSESSMENT\nThis 200-item assessment is designed for mid-career professionals (3-15 years of experience) working in B2C contexts. Items reflect the complexity of leading teams, managing accounts, navigating mid-career identity, and operating in a digital-first commercial environment. Calibration is significantly more demanding than the fresher assessments - distractors are subtler and scenarios closer to lived complexity.\n\nHOW TO TAKE THIS ASSESSMENT\nSix psychometrically distinct item types are used. For self-concept items, there is no \'right\' answer - they measure your perception of yourself. For situational judgment items, all options reflect things real professionals do; choose what you would genuinely do, not what sounds best.\n\nTIME REQUIRED: 75-90 minutes. May be split across two sittings.\n\nITEM TYPES IN THIS ASSESSMENT\n• K — Knowledge MCQ: One correct answer. Choose the best response based on your knowledge.\n• SJT — Situational Judgment: All options are plausible. Choose what you would most likely do in real life.\n• SCI — Self-Concept Inventory: No right or wrong answer — answer honestly about yourself.\n• SCI-R — Reverse-Coded Self-Concept: No right or wrong answer — answer honestly (some items are reverse-coded).\n• BEH — Behavioral Frequency: Rate how often this applies to you (Never → Always).\n• FC — Forced Choice: Select the BEST and WORST option from the choices given.\n\nPILLAR WEIGHTS (for composite score)\n• Value Selling Mastery — 45 items (22%)\n• Leadership & Influence — 45 items (22%)\n• Personality & Communication — 40 items (20%)\n• Mental Wellness & Resilience — 35 items (18%)\n• Technology & Digital Fluency — 35 items (18%)\n\nPROFICIENCY BANDS\n• ADVANCED (85–100): Demonstrates sustained mastery. Ready for senior responsibility, mentoring others, and leading complex initiatives.\n• PROFICIENT (70–84): Reliably effective in most situations. Benefits from stretch assignments and exposure to higher-complexity challenges.\n• COMPETENT (50–69): Solid foundation with room to deepen. Coaching, applied practice, and structured feedback will accelerate development.\n• EMERGING (30–49): Foundational understanding but inconsistent application. Needs targeted skill-building and supervised practice.\n• DEVELOPING (0–29): Significant gap. Requires intensive learning, mentorship, and behavioral coaching before independent responsibility is appropriate.',90,200,'P3','{\"header\":\"ELEVATES   |   PROFESSIONAL GROWTH ASSESSMENT\",\"persona\":\"PERSONA 03\",\"title\":\"Working Professionals\",\"name\":\"Working Professionals\",\"context_line\":\"Experience  ·  3–15 years        Context  ·  B2C context        Difficulty  ·  Intermediate–Advanced\",\"tagline\":\"A 200-item, multi-format, psychometrically structured assessment covering five pillars of professional growth.\",\"pillars\":[{\"num\":\"01\",\"name\":\"Value Selling Mastery\"},{\"num\":\"02\",\"name\":\"Leadership & Influence\"},{\"num\":\"03\",\"name\":\"Personality & Communication\"},{\"num\":\"04\",\"name\":\"Mental Wellness & Resilience\"},{\"num\":\"05\",\"name\":\"Technology & Digital Fluency\"}],\"about\":\"This 200-item assessment is designed for mid-career professionals (3-15 years of experience) working in B2C contexts. Items reflect the complexity of leading teams, managing accounts, navigating mid-career identity, and operating in a digital-first commercial environment. Calibration is significantly more demanding than the fresher assessments - distractors are subtler and scenarios closer to lived complexity.\",\"how_to\":\"Six psychometrically distinct item types are used. For self-concept items, there is no \'right\' answer - they measure your perception of yourself. For situational judgment items, all options reflect things real professionals do; choose what you would genuinely do, not what sounds best.\",\"time_required\":\"75-90 minutes. May be split across two sittings.\",\"pillar_weights\":[{\"num\":\"01\",\"name\":\"Value Selling Mastery\",\"items\":45,\"weight\":\"22%\",\"weight_pct\":22},{\"num\":\"02\",\"name\":\"Leadership & Influence\",\"items\":45,\"weight\":\"22%\",\"weight_pct\":22},{\"num\":\"03\",\"name\":\"Personality & Communication\",\"items\":40,\"weight\":\"20%\",\"weight_pct\":20},{\"num\":\"04\",\"name\":\"Mental Wellness & Resilience\",\"items\":35,\"weight\":\"18%\",\"weight_pct\":18},{\"num\":\"05\",\"name\":\"Technology & Digital Fluency\",\"items\":35,\"weight\":\"18%\",\"weight_pct\":18}],\"scoring_steps\":[\"STEP 1  Compute the raw score for each pillar by summing item-level scores using the Answer Key. Knowledge items contribute 0–1; SJT items contribute 0–3; Self-concept and behavioral items contribute 1–5.\",\"STEP 2  Convert each pillar\'s raw score to a percentage of its maximum possible score: Pillar % = (raw \\/ max) × 100. Round to one decimal place.\",\"STEP 3  Compute the Composite Score as the weighted average of pillar percentages: Composite = Σ (Pillar % × Pillar Weight) ÷ 100.\",\"STEP 4  Map both pillar percentages and composite score to the five proficiency bands in section 4 to derive the descriptive level and recommended interventions.\"],\"proficiency_bands\":[{\"min\":85,\"max\":100,\"title\":\"ADVANCED\",\"descriptor\":\"Demonstrates sustained mastery. Ready for senior responsibility, mentoring others, and leading complex initiatives.\"},{\"min\":70,\"max\":84,\"title\":\"PROFICIENT\",\"descriptor\":\"Reliably effective in most situations. Benefits from stretch assignments and exposure to higher-complexity challenges.\"},{\"min\":50,\"max\":69,\"title\":\"COMPETENT\",\"descriptor\":\"Solid foundation with room to deepen. Coaching, applied practice, and structured feedback will accelerate development.\"},{\"min\":30,\"max\":49,\"title\":\"EMERGING\",\"descriptor\":\"Foundational understanding but inconsistent application. Needs targeted skill-building and supervised practice.\"},{\"min\":0,\"max\":29,\"title\":\"DEVELOPING\",\"descriptor\":\"Significant gap. Requires intensive learning, mentorship, and behavioral coaching before independent responsibility is appropriate.\"}],\"item_types\":[{\"code\":\"K\",\"name\":\"Knowledge MCQ\",\"hint\":\"One correct answer. Choose the best response based on your knowledge.\"},{\"code\":\"SJT\",\"name\":\"Situational Judgment\",\"hint\":\"All options are plausible. Choose what you would most likely do in real life.\"},{\"code\":\"SCI\",\"name\":\"Self-Concept Inventory\",\"hint\":\"No right or wrong answer — answer honestly about yourself.\"},{\"code\":\"SCI-R\",\"name\":\"Reverse-Coded Self-Concept\",\"hint\":\"No right or wrong answer — answer honestly (some items are reverse-coded).\"},{\"code\":\"BEH\",\"name\":\"Behavioral Frequency\",\"hint\":\"Rate how often this applies to you (Never → Always).\"},{\"code\":\"FC\",\"name\":\"Forced Choice\",\"hint\":\"Select the BEST and WORST option from the choices given.\"}],\"code\":\"P3\",\"sort_order\":3,\"slug\":\"working-professionals\"}'),(8,'Corporate Professionals','PERSONA 04\nExperience  ·  3-15 years        Context  ·  B2B / Enterprise        Difficulty  ·  Intermediate-Advanced\n\nThis 200-item assessment is designed for corporate professionals with 3-15 years of experience in B2B/enterprise contexts. Items reflect the complexity of enterprise sales cycles, matrix organisational structures, executive communication, and the technology governance expectations of modern corporate work.\nCalibration vs. earlier-career assessments\nItems here assume direct experience with enterprise complexity: MEDDIC qualification, multi-stakeholder selling, matrix navigation, board-level comm…',4,'active','2026-06-25 17:31:35','ELEVATES   |   PROFESSIONAL GROWTH ASSESSMENT\nPERSONA 04 — Corporate Professionals\nExperience  ·  3-15 years        Context  ·  B2B / Enterprise        Difficulty  ·  Intermediate-Advanced\n\nA 200-item, multi-format, psychometrically structured assessment covering five pillars of professional growth.\n\nFIVE PILLARS ASSESSED\n01  Value Selling Mastery\n02  Leadership & Influence\n03  Personality & Communication\n04  Mental Wellness & Resilience\n05  Technology & Digital Fluency\n\nABOUT THIS ASSESSMENT\nThis 200-item assessment is designed for corporate professionals with 3-15 years of experience in B2B/enterprise contexts. Items reflect the complexity of enterprise sales cycles, matrix organisational structures, executive communication, and the technology governance expectations of modern corporate work.\nCalibration vs. earlier-career assessments\nItems here assume direct experience with enterprise complexity: MEDDIC qualification, multi-stakeholder selling, matrix navigation, board-level communication, sustained-performance management at senior levels, and enterprise technology governance including AI deployment.\n\nHOW TO TAKE THIS ASSESSMENT\nAnswer honestly. Self-concept items have no \'right\' answer. Time required: 75-90 minutes.\n\nITEM TYPES IN THIS ASSESSMENT\n• K — Knowledge MCQ: One correct answer. Choose the best response based on your knowledge.\n• SJT — Situational Judgment: All options are plausible. Choose what you would most likely do in real life.\n• SCI — Self-Concept Inventory: No right or wrong answer — answer honestly about yourself.\n• SCI-R — Reverse-Coded Self-Concept: No right or wrong answer — answer honestly (some items are reverse-coded).\n• BEH — Behavioral Frequency: Rate how often this applies to you (Never → Always).\n• FC — Forced Choice: Select the BEST and WORST option from the choices given.\n\nPILLAR WEIGHTS (for composite score)\n• Value Selling Mastery — 50 items (24%)\n• Leadership & Influence — 50 items (24%)\n• Personality & Communication — 40 items (22%)\n• Mental Wellness & Resilience — 30 items (15%)\n• Technology & Digital Fluency — 30 items (15%)\n\nPROFICIENCY BANDS\n• ADVANCED (85–100): Demonstrates sustained mastery. Ready for senior responsibility, mentoring others, and leading complex initiatives.\n• PROFICIENT (70–84): Reliably effective in most situations. Benefits from stretch assignments and exposure to higher-complexity challenges.\n• COMPETENT (50–69): Solid foundation with room to deepen. Coaching, applied practice, and structured feedback will accelerate development.\n• EMERGING (30–49): Foundational understanding but inconsistent application. Needs targeted skill-building and supervised practice.\n• DEVELOPING (0–29): Significant gap. Requires intensive learning, mentorship, and behavioral coaching before independent responsibility is appropriate.',90,200,'P4','{\"header\":\"ELEVATES   |   PROFESSIONAL GROWTH ASSESSMENT\",\"persona\":\"PERSONA 04\",\"title\":\"Corporate Professionals\",\"name\":\"Corporate Professionals\",\"context_line\":\"Experience  ·  3-15 years        Context  ·  B2B \\/ Enterprise        Difficulty  ·  Intermediate-Advanced\",\"tagline\":\"A 200-item, multi-format, psychometrically structured assessment covering five pillars of professional growth.\",\"pillars\":[{\"num\":\"01\",\"name\":\"Value Selling Mastery\"},{\"num\":\"02\",\"name\":\"Leadership & Influence\"},{\"num\":\"03\",\"name\":\"Personality & Communication\"},{\"num\":\"04\",\"name\":\"Mental Wellness & Resilience\"},{\"num\":\"05\",\"name\":\"Technology & Digital Fluency\"}],\"about\":\"This 200-item assessment is designed for corporate professionals with 3-15 years of experience in B2B\\/enterprise contexts. Items reflect the complexity of enterprise sales cycles, matrix organisational structures, executive communication, and the technology governance expectations of modern corporate work.\\nCalibration vs. earlier-career assessments\\nItems here assume direct experience with enterprise complexity: MEDDIC qualification, multi-stakeholder selling, matrix navigation, board-level communication, sustained-performance management at senior levels, and enterprise technology governance including AI deployment.\",\"how_to\":\"Answer honestly. Self-concept items have no \'right\' answer. Time required: 75-90 minutes.\",\"pillar_weights\":[{\"num\":\"01\",\"name\":\"Value Selling Mastery\",\"items\":50,\"weight\":\"24%\",\"weight_pct\":24},{\"num\":\"02\",\"name\":\"Leadership & Influence\",\"items\":50,\"weight\":\"24%\",\"weight_pct\":24},{\"num\":\"03\",\"name\":\"Personality & Communication\",\"items\":40,\"weight\":\"22%\",\"weight_pct\":22},{\"num\":\"04\",\"name\":\"Mental Wellness & Resilience\",\"items\":30,\"weight\":\"15%\",\"weight_pct\":15},{\"num\":\"05\",\"name\":\"Technology & Digital Fluency\",\"items\":30,\"weight\":\"15%\",\"weight_pct\":15}],\"scoring_steps\":[\"STEP 1  Compute the raw score for each pillar by summing item-level scores using the Answer Key. Knowledge items contribute 0–1; SJT items contribute 0–3; Self-concept and behavioral items contribute 1–5.\",\"STEP 2  Convert each pillar\'s raw score to a percentage of its maximum possible score: Pillar % = (raw \\/ max) × 100. Round to one decimal place.\",\"STEP 3  Compute the Composite Score as the weighted average of pillar percentages: Composite = Σ (Pillar % × Pillar Weight) ÷ 100.\",\"STEP 4  Map both pillar percentages and composite score to the five proficiency bands in section 4 to derive the descriptive level and recommended interventions.\"],\"proficiency_bands\":[{\"min\":85,\"max\":100,\"title\":\"ADVANCED\",\"descriptor\":\"Demonstrates sustained mastery. Ready for senior responsibility, mentoring others, and leading complex initiatives.\"},{\"min\":70,\"max\":84,\"title\":\"PROFICIENT\",\"descriptor\":\"Reliably effective in most situations. Benefits from stretch assignments and exposure to higher-complexity challenges.\"},{\"min\":50,\"max\":69,\"title\":\"COMPETENT\",\"descriptor\":\"Solid foundation with room to deepen. Coaching, applied practice, and structured feedback will accelerate development.\"},{\"min\":30,\"max\":49,\"title\":\"EMERGING\",\"descriptor\":\"Foundational understanding but inconsistent application. Needs targeted skill-building and supervised practice.\"},{\"min\":0,\"max\":29,\"title\":\"DEVELOPING\",\"descriptor\":\"Significant gap. Requires intensive learning, mentorship, and behavioral coaching before independent responsibility is appropriate.\"}],\"item_types\":[{\"code\":\"K\",\"name\":\"Knowledge MCQ\",\"hint\":\"One correct answer. Choose the best response based on your knowledge.\"},{\"code\":\"SJT\",\"name\":\"Situational Judgment\",\"hint\":\"All options are plausible. Choose what you would most likely do in real life.\"},{\"code\":\"SCI\",\"name\":\"Self-Concept Inventory\",\"hint\":\"No right or wrong answer — answer honestly about yourself.\"},{\"code\":\"SCI-R\",\"name\":\"Reverse-Coded Self-Concept\",\"hint\":\"No right or wrong answer — answer honestly (some items are reverse-coded).\"},{\"code\":\"BEH\",\"name\":\"Behavioral Frequency\",\"hint\":\"Rate how often this applies to you (Never → Always).\"},{\"code\":\"FC\",\"name\":\"Forced Choice\",\"hint\":\"Select the BEST and WORST option from the choices given.\"}],\"code\":\"P4\",\"sort_order\":4,\"slug\":\"corporate-professionals\"}'),(9,'Senior Executives','PERSONA 05\nExperience  ·  15+ years        Context  ·  B2B / C-Suite        Difficulty  ·  Advanced-Strategic\n\nThis 200-item assessment is designed for senior executives operating at C-suite, board, and other senior leadership levels. Items reflect the complexity of organisational strategy, capital allocation, executive communication, sustained performance over decades, and the technology governance expectations facing modern senior leaders.\nCalibration vs. earlier-career assessments\nItems here assume direct experience with senior-level work: board engagement, executive team leadership, public communica…',5,'active','2026-06-25 17:31:36','ELEVATES   |   PROFESSIONAL GROWTH ASSESSMENT\nPERSONA 05 — Senior Executives\nExperience  ·  15+ years        Context  ·  B2B / C-Suite        Difficulty  ·  Advanced-Strategic\n\nA 200-item, multi-format, psychometrically structured assessment covering five pillars of professional growth.\n\nFIVE PILLARS ASSESSED\n01  Value Selling Mastery\n02  Leadership & Influence\n03  Personality & Communication\n04  Mental Wellness & Resilience\n05  Technology & Digital Fluency\n\nABOUT THIS ASSESSMENT\nThis 200-item assessment is designed for senior executives operating at C-suite, board, and other senior leadership levels. Items reflect the complexity of organisational strategy, capital allocation, executive communication, sustained performance over decades, and the technology governance expectations facing modern senior leaders.\nCalibration vs. earlier-career assessments\nItems here assume direct experience with senior-level work: board engagement, executive team leadership, public communication at scale, capital allocation decisions, crisis management, and the structural challenges of sustained high performance over years. Distractors are designed to be plausible to senior leaders - including common patterns that look reasonable but are sub-optimal.\n\nHOW TO TAKE THIS ASSESSMENT\nAnswer honestly. Self-concept items have no \'right\' answer - they measure your perception of yourself. Situational judgment items present scenarios where multiple options reflect things experienced senior leaders actually do; the highest-scoring answer reflects the response with strongest evidence base or strategic merit. Time required: 75-90 minutes.\n\nITEM TYPES IN THIS ASSESSMENT\n• K — Knowledge MCQ: One correct answer. Choose the best response based on your knowledge.\n• SJT — Situational Judgment: All options are plausible. Choose what you would most likely do in real life.\n• SCI — Self-Concept Inventory: No right or wrong answer — answer honestly about yourself.\n• SCI-R — Reverse-Coded Self-Concept: No right or wrong answer — answer honestly (some items are reverse-coded).\n• BEH — Behavioral Frequency: Rate how often this applies to you (Never → Always).\n• FC — Forced Choice: Select the BEST and WORST option from the choices given.\n\nPILLAR WEIGHTS (for composite score)\n• Value Selling Mastery — 35 items (15%)\n• Leadership & Influence — 70 items (30%)\n• Personality & Communication — 40 items (22%)\n• Mental Wellness & Resilience — 25 items (15%)\n• Technology & Digital Fluency — 30 items (18%)\n\nPROFICIENCY BANDS\n• ADVANCED (85–100): Demonstrates sustained mastery. Ready for senior responsibility, mentoring others, and leading complex initiatives.\n• PROFICIENT (70–84): Reliably effective in most situations. Benefits from stretch assignments and exposure to higher-complexity challenges.\n• COMPETENT (50–69): Solid foundation with room to deepen. Coaching, applied practice, and structured feedback will accelerate development.\n• EMERGING (30–49): Foundational understanding but inconsistent application. Needs targeted skill-building and supervised practice.\n• DEVELOPING (0–29): Significant gap. Requires intensive learning, mentorship, and behavioral coaching before independent responsibility is appropriate.',90,200,'P5','{\"header\":\"ELEVATES   |   PROFESSIONAL GROWTH ASSESSMENT\",\"persona\":\"PERSONA 05\",\"title\":\"Senior Executives\",\"name\":\"Senior Executives\",\"context_line\":\"Experience  ·  15+ years        Context  ·  B2B \\/ C-Suite        Difficulty  ·  Advanced-Strategic\",\"tagline\":\"A 200-item, multi-format, psychometrically structured assessment covering five pillars of professional growth.\",\"pillars\":[{\"num\":\"01\",\"name\":\"Value Selling Mastery\"},{\"num\":\"02\",\"name\":\"Leadership & Influence\"},{\"num\":\"03\",\"name\":\"Personality & Communication\"},{\"num\":\"04\",\"name\":\"Mental Wellness & Resilience\"},{\"num\":\"05\",\"name\":\"Technology & Digital Fluency\"}],\"about\":\"This 200-item assessment is designed for senior executives operating at C-suite, board, and other senior leadership levels. Items reflect the complexity of organisational strategy, capital allocation, executive communication, sustained performance over decades, and the technology governance expectations facing modern senior leaders.\\nCalibration vs. earlier-career assessments\\nItems here assume direct experience with senior-level work: board engagement, executive team leadership, public communication at scale, capital allocation decisions, crisis management, and the structural challenges of sustained high performance over years. Distractors are designed to be plausible to senior leaders - including common patterns that look reasonable but are sub-optimal.\",\"how_to\":\"Answer honestly. Self-concept items have no \'right\' answer - they measure your perception of yourself. Situational judgment items present scenarios where multiple options reflect things experienced senior leaders actually do; the highest-scoring answer reflects the response with strongest evidence base or strategic merit. Time required: 75-90 minutes.\",\"pillar_weights\":[{\"num\":\"01\",\"name\":\"Value Selling Mastery\",\"items\":35,\"weight\":\"15%\",\"weight_pct\":15},{\"num\":\"02\",\"name\":\"Leadership & Influence\",\"items\":70,\"weight\":\"30%\",\"weight_pct\":30},{\"num\":\"03\",\"name\":\"Personality & Communication\",\"items\":40,\"weight\":\"22%\",\"weight_pct\":22},{\"num\":\"04\",\"name\":\"Mental Wellness & Resilience\",\"items\":25,\"weight\":\"15%\",\"weight_pct\":15},{\"num\":\"05\",\"name\":\"Technology & Digital Fluency\",\"items\":30,\"weight\":\"18%\",\"weight_pct\":18}],\"scoring_steps\":[\"STEP 1  Compute the raw score for each pillar by summing item-level scores using the Answer Key. Knowledge items contribute 0–1; SJT items contribute 0–3; Self-concept and behavioral items contribute 1–5.\",\"STEP 2  Convert each pillar\'s raw score to a percentage of its maximum possible score: Pillar % = (raw \\/ max) × 100. Round to one decimal place.\",\"STEP 3  Compute the Composite Score as the weighted average of pillar percentages: Composite = Σ (Pillar % × Pillar Weight) ÷ 100.\",\"STEP 4  Map both pillar percentages and composite score to the five proficiency bands in section 4 to derive the descriptive level and recommended interventions.\"],\"proficiency_bands\":[{\"min\":85,\"max\":100,\"title\":\"ADVANCED\",\"descriptor\":\"Demonstrates sustained mastery. Ready for senior responsibility, mentoring others, and leading complex initiatives.\"},{\"min\":70,\"max\":84,\"title\":\"PROFICIENT\",\"descriptor\":\"Reliably effective in most situations. Benefits from stretch assignments and exposure to higher-complexity challenges.\"},{\"min\":50,\"max\":69,\"title\":\"COMPETENT\",\"descriptor\":\"Solid foundation with room to deepen. Coaching, applied practice, and structured feedback will accelerate development.\"},{\"min\":30,\"max\":49,\"title\":\"EMERGING\",\"descriptor\":\"Foundational understanding but inconsistent application. Needs targeted skill-building and supervised practice.\"},{\"min\":0,\"max\":29,\"title\":\"DEVELOPING\",\"descriptor\":\"Significant gap. Requires intensive learning, mentorship, and behavioral coaching before independent responsibility is appropriate.\"}],\"item_types\":[{\"code\":\"K\",\"name\":\"Knowledge MCQ\",\"hint\":\"One correct answer. Choose the best response based on your knowledge.\"},{\"code\":\"SJT\",\"name\":\"Situational Judgment\",\"hint\":\"All options are plausible. Choose what you would most likely do in real life.\"},{\"code\":\"SCI\",\"name\":\"Self-Concept Inventory\",\"hint\":\"No right or wrong answer — answer honestly about yourself.\"},{\"code\":\"SCI-R\",\"name\":\"Reverse-Coded Self-Concept\",\"hint\":\"No right or wrong answer — answer honestly (some items are reverse-coded).\"},{\"code\":\"BEH\",\"name\":\"Behavioral Frequency\",\"hint\":\"Rate how often this applies to you (Never → Always).\"},{\"code\":\"FC\",\"name\":\"Forced Choice\",\"hint\":\"Select the BEST and WORST option from the choices given.\"}],\"code\":\"P5\",\"sort_order\":5,\"slug\":\"senior-executives\"}');
