INSERT INTO `quiz_result_bands` (`id`, `min_percent`, `max_percent`, `title`, `result_text`, `sort_order`, `created_at`) VALUES (14,85.00,100.00,'ADVANCED','Demonstrates sustained mastery. Ready for senior responsibility, mentoring others, and leading complex initiatives.',1,'2026-06-25 18:00:48'),(15,70.00,84.00,'PROFICIENT','Reliably effective in most situations. Benefits from stretch assignments and exposure to higher-complexity challenges.',2,'2026-06-25 18:00:48'),(16,50.00,69.00,'COMPETENT','Solid foundation with room to deepen. Coaching, applied practice, and structured feedback will accelerate development.',3,'2026-06-25 18:00:48'),(17,30.00,49.00,'EMERGING','Foundational understanding but inconsistent application. Needs targeted skill-building and supervised practice.',4,'2026-06-25 18:00:48'),(18,0.00,29.00,'DEVELOPING','Significant gap. Requires intensive learning, mentorship, and behavioral coaching before independent responsibility is appropriate.',5,'2026-06-25 18:00:48');
